def allow(key, now, bucket):
    # sliding window: drop entries older than 60s, accept if < 10 remain
    bucket[key] = [t for t in bucket.get(key, []) if now - t < 60]
    if len(bucket[key]) < 10:
        bucket[key].append(now)
        return True
    return False


def allow_ip(ip, now, bucket):
    """Per-IP variant of allow(). Namespaces the key so IP buckets can't
    collide with other key types sharing the same dict."""
    if not isinstance(ip, str) or not ip:
        raise ValueError("ip must be a non-empty string")
    return allow(("ip", ip), now, bucket)

